def solve(nums=None, target=None):
    if nums is None or target is None:
        return {"status": "error", "message": "Missing required parameters"}

    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1
